    "buckets" : {
      "buckets" : [
        {
          "key_as_string" : "2019-07-15T00:00:00.000Z",
          "key" : 1563148800000,
          "doc_count" : 1,
          "avg" : {
            "value" : 1.563209431E12,
            "value_as_string" : "2019-07-15T16:50:31.000Z"
          }
        },
        {
